function bar(milestones: Milestone[], totalMs: number): string {
  const ach   = new Set(milestones.map(m => m.id));
  const pct   = Math.min(100, (totalMs / GOAL_BUDGET_MS) * 100);
  const col   = totalMs <= GOAL_BUDGET_MS ? '#3fb950' : '#f85149';
  const steps = MILESTONE_DEFS.map(def => {
    const hit  = milestones.find(m => m.id === def.id);
    const done = ach.has(def.id);
    return `<div class="mst ${done ? 'msd' : 'msp'}"><div class="md">${done ? '&#10003;' : ''}</div><div class="ml">${esc(def.label)}</div>${hit ? `<div class="mt">${fmtMs(hit.elapsed_ms)}</div><div class="mev">${esc(hit.evidence)}</div>` : ''}</div>`;
  }).join('');
  return `<div class="mb">${steps}<div class="bw"><div class="bl">Time vs 10-min goal</div><div class="bt"><div class="bf" style="width:${pct.toFixed(1)}%;background:${col}"></div><div class="bti"></div></div><div class="be" style="color:${col}">${fmtMs(totalMs)} / 10:00</div></div></div>`;
}

function renderTurn(t: TurnRecord): string {
  const col     = agentColor(t.agent);
  const msb     = t.milestones.map(m => `<div class="msb">&#127937; ${esc(m.label)}<span class="msbe">${esc(m.evidence)}</span></div>`).join('');
  const th      = t.toolCalls.length ? `<div class="tr">&#128295; ${t.toolCalls.map(tc => `<code>${esc(tc)}</code>`).join(' ')}</div>` : '';
  const ah      = t.actions.length ? `<div class="ar">${t.actions.map(a => `<span class="ac">${esc(a.agentInput)}</span>`).join('')}</div>` : '';
  const txh     = t.silent
    ? `<span style="color:#f85149;font-weight:600">🔴 SILENT — agent produced no text${t.logs.length ? '<br><code style=\'font-size:10px;color:#f0883e\'>' + t.logs.map(esc).join('<br>') + '</code>' : ''}</span>`
    : (t.text.includes('\n') ? `<pre>${esc(t.text)}</pre>` : esc(t.text));
  const aiBadge = t.personaGenerated ? `<div class="ai-badge">&#129302; AI persona</div>` : '';
  const fColor  = frustrationColor(t.frustration);
  const fLabel  = t.personaGenerated
    ? `<div class="f-badge" style="color:${fColor};border-color:${fColor}" title="Frustration ${t.frustration}/5">${frustrationEmoji(t.frustration)} ${frustrationBar(t.frustration)}</div>`
    : '';
  const silentBorder = t.silent ? 'border:1px solid #da3633;background:#1a0a0a;' : `border-left-color:${col}`;
  return `<div class="turn">
    <div class="tu">${aiBadge}<div class="bu${t.personaGenerated ? ' bu-ai' : ''}" style="${t.personaGenerated ? `border-left:3px solid ${fColor}` : ''}">${esc(t.userInput)}</div>${fLabel}<div class="tm">T${t.turn} &mdash; ${fmtMs(t.elapsed_ms)}</div></div>
    ${msb}
    <div class="ta"><div class="al" style="color:${col}">&#9679; ${esc(t.agent)}</div>${th}<div class="ba" style="${silentBorder}">${txh}</div>${ah}</div>
  </div>`;
}

function frustrationSparkline(turns: TurnRecord[]): string {
  const generated = turns.filter(t => t.personaGenerated);
  if (!generated.length) return '';
  const max = 5;
  const h   = 32;
  const w   = Math.max(generated.length * 12, 60);
  const pts = generated.map((t, i) => {
    const x = (i / Math.max(generated.length - 1, 1)) * (w - 4) + 2;
    const y = h - 2 - ((t.frustration / max) * (h - 4));
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  }).join(' ');
  const avg = generated.reduce((s, t) => s + t.frustration, 0) / generated.length;
  const avgColor = frustrationColor(Math.round(avg));
  return `<div style="display:flex;align-items:center;gap:10px;margin-top:8px">
    <span style="font-size:11px;color:#8b949e;font-weight:600;text-transform:uppercase;letter-spacing:.05em">Frustration</span>
    <svg width="${w}" height="${h}" style="overflow:visible">
      <polyline points="${pts}" fill="none" stroke="${avgColor}" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
      ${generated.map((t, i) => {
        const x = (i / Math.max(generated.length - 1, 1)) * (w - 4) + 2;
        const y = h - 2 - ((t.frustration / max) * (h - 4));
        return `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="3" fill="${frustrationColor(t.frustration)}" title="T${t.turn}: ${t.frustration}/5"/>`;
      }).join('')}
    </svg>
    <span style="font-size:12px;font-weight:700;color:${avgColor}">${frustrationEmoji(Math.round(avg))} avg ${avg.toFixed(1)}/5</span>
  </div>`;
}

function simPage(r: SimResult): string {
  const ach = new Set(r.milestones.map(m => m.id));
  const ts  = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>${esc(r.persona.id)}: ${esc(r.persona.title)}</title><style>${CSS}</style></head><body>
<div class="ph"><div><a class="back" href="index.html">&larr; All personas</a><h1>&#129302; ${esc(r.persona.title)}</h1></div>
<span style="color:#6e7681;font-size:12px">${ts}</span><div class="gb ${r.goalMet ? 'gm' : 'gnm'}">${r.goalMet ? '&#9989; Goal met' : '&#10060; Not met'}</div></div>
${bar(r.milestones, r.duration_ms)}
<div class="sm"><div class="so">&ldquo;${esc(r.persona.opener)}&rdquo;</div>
<div class="ss">${r.turns.length} turns &middot; ${fmtMs(r.duration_ms)} &middot; ${ach.size}/6 milestones &middot; <span style="color:#58a6ff">&#129302; AI-driven responses</span></div>
${frustrationSparkline(r.turns)}</div>
${r.error ? `<div class="eb">&#9888; ${esc(r.error)}</div>` : ''}
<div class="turns">${r.turns.map(renderTurn).join('\n')}</div></body></html>`;
}

function indexPage(results: SimResult[]): string {
  const ts    = new Date().toISOString().replace('T', ' ').slice(0, 19) + ' UTC';
  const cards = results.map(r => {
    const ach    = new Set(r.milestones.map(m => m.id));
    const badges = MILESTONE_DEFS.map(d => `<span class="${ach.has(d.id) ? 'mh' : 'mm'}">${d.label}</span>`).join('');
    return `<a class="sc" href="${esc(r.persona.id)}.html"><div class="sci">${esc(r.persona.id)} &middot; &#129302; AI persona</div>
<div class="sct">${esc(r.persona.title)}</div><div class="scm">${badges}</div>
<div class="sct2">${ach.size}/6 &middot; ${fmtMs(r.duration_ms)} &middot; <strong style="color:${r.goalMet ? '#3fb950' : '#f85149'}">${r.goalMet ? '&#9989; Met' : '&#10060; Not met'}</strong></div></a>`;
  }).join('');
  return `<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>Persona Sim Report</title><style>${CSS}</style></head><body>
<div class="ph"><h1>&#127919; Deploy to AKS Automatic &mdash; AI Persona Sims</h1>
<span style="color:#8b949e;font-size:13px">${ts} &middot; goal: 10 min &middot; &#129302; AI-driven personas</span></div>
<div class="ii">Each card links to the full conversation. User responses were generated by an LLM adopting the persona — pushing back when frustrated, picking actions, driving toward deployment.</div>
<div class="ig">${cards}</div></body></html>`;
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

async function main(): Promise<void> {
  const count  = parseInt(args.count ?? '3', 10);
  const client = buildPersonaClient();

  const personas = await generatePersonas(client, count);
  if (!personas.length) { process.stderr.write('No personas generated\n'); process.exit(1); }

  fs.mkdirSync(REPORTS_DIR, { recursive: true });

  process.stderr.write(`\n[Goal] Deploy to AKS Automatic in < 10 minutes\n`);
  process.stderr.write(`[Mode] AI-driven personas (LLM generates each response)\n`);
  process.stderr.write(`[Max ] ${MAX_TURNS} turns per persona\n`);
  process.stderr.write(`Running ${personas.length} persona(s)...\n\n`);

  const results: SimResult[] = [];

  for (const persona of personas) {
    process.stderr.write(`  ${persona.id}: ${persona.title}\n  ${'─'.repeat(60)}\n`);
    const result = await runPersona(persona, client);
    results.push(result);
    process.stderr.write(`\n  ${result.goalMet ? '[GOAL MET]' : '[NOT MET]'} ${result.milestones.length}/6 milestones in ${fmtMs(result.duration_ms)}\n`);

    const outFile = path.join(REPORTS_DIR, `${persona.id}.html`);
    fs.writeFileSync(outFile, simPage(result), 'utf8');
    process.stderr.write(`  -> ${outFile}\n\n`);

    fs.writeFileSync(path.join(REPORTS_DIR, 'index.html'), indexPage(results), 'utf8');
  }

  process.stderr.write(`All done -> ${path.join(REPORTS_DIR, 'index.html')}\n`);
}

main().catch((e: unknown) => { process.stderr.write(`Fatal: ${e}\n`); process.exit(1); });
